# Manual iterator protocol
class Range:
    def __init__(self, start, stop):
        self.current = start; self.stop = stop

    def __iter__(self):
        return self    # this object is both iterable and iterator

    def __next__(self):
        if self.current >= self.stop:
            raise StopIteration
        val = self.current; self.current += 1
        return val

for x in Range(1, 4): print(x)  # 1 2 3

# 'for x in iterable' desugars to:
it = iter(iterable)   # calls iterable.__iter__()
while True:
    try:
        x = next(it)  # calls it.__next__()
        # ... loop body ...
    except StopIteration:
        break

# for/else — search without a flag variable
def find_prime_factor(n):
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return i   # found a factor
    else:
        return n       # else runs only if loop didn't break

# Two-pointer skeleton
def two_pointer_sorted(arr, target):
    lo, hi = 0, len(arr) - 1
    while lo < hi:
        s = arr[lo] + arr[hi]
        if s == target: return lo, hi
        elif s < target: lo += 1
        else: hi -= 1
    return None

# Sliding window skeleton
def max_subarray_sum(arr, k):
    window_sum = sum(arr[:k])
    max_sum = window_sum
    for i in range(k, len(arr)):
        window_sum += arr[i] - arr[i-k]  # add new, remove old
        max_sum = max(max_sum, window_sum)
    return max_sum
